import { TestIds } from '../../constants.js';

interface LineIndicatorProps {
  x: number;
  height: number;
  color: string;
  filter: string;
}

export const LineIndicator = ({
  x,
  height,
  color,
  filter,
}: LineIndicatorProps) => (
  <line
    data-testid={TestIds.AnnotationIndicator}
    x1={x}
    x2={x}
    y1={0}
    y2={height}
    stroke={color}
    strokeWidth={1}
    filter={filter}
  />
);
